INSERT INTO place_content (id, place_id, content_type, title, title_hi, content, content_hi, status, created_at, updated_at) VALUES 
(gen_random_uuid(), (SELECT id FROM places WHERE name = 'Agra' LIMIT 1), 'HISTORICAL', 'Historical Overview of Agra', 'Agra का ऐतिहासिक अवलोकन', '{"historical": "Agra was the capital of the Mughal Empire under emperors like Akbar, Jahangir, and Shah Jahan. It is home to the iconic Taj Mahal, built in the 17th century.", "cultural": "The city represents the pinnacle of Mughal art and architecture, blending Indian, Persian, and Islamic styles. It is a UNESCO World Heritage hub."}'::jsonb, '{"historical": "\u0906\u0917\u0930\u093e \u0905\u0915\u092c\u0930, \u091c\u0939\u093e\u0902\u0917\u0940\u0930 \u0914\u0930 \u0936\u093e\u0939\u091c\u0939\u093e\u0902 \u091c\u0948\u0938\u0947 \u0938\u092e\u094d\u0930\u093e\u091f\u094b\u0902 \u0915\u0947 \u0905\u0927\u0940\u0928 \u092e\u0941\u0917\u0932 \u0938\u093e\u092e\u094d\u0930\u093e\u091c\u094d\u092f \u0915\u0940 \u0930\u093e\u091c\u0927\u093e\u0928\u0940 \u0925\u093e\u0964 \u092f\u0939 17\u0935\u0940\u0902 \u0938\u0926\u0940 \u092e\u0947\u0902 \u092c\u0928\u0947 \u092a\u094d\u0930\u0924\u093f\u0937\u094d\u0920\u093f\u0924 \u0924\u093e\u091c\u092e\u0939\u0932 \u0915\u093e \u0918\u0930 \u0939\u0948\u0964", "cultural": "\u092f\u0939 \u0936\u0939\u0930 \u092e\u0941\u0917\u0932 \u0915\u0932\u093e \u0914\u0930 \u0935\u093e\u0938\u094d\u0924\u0941\u0915\u0932\u093e \u0915\u0947 \u091a\u0930\u092e\u094b\u0924\u094d\u0915\u0930\u094d\u0937 \u0915\u093e \u092a\u094d\u0930\u0924\u093f\u0928\u093f\u0927\u093f\u0924\u094d\u0935 \u0915\u0930\u0924\u093e \u0939\u0948, \u091c\u093f\u0938\u092e\u0947\u0902 \u092d\u093e\u0930\u0924\u0940\u092f, \u092b\u093e\u0930\u0938\u0940 \u0914\u0930 \u0907\u0938\u094d\u0932\u093e\u092e\u0940 \u0936\u0948\u0932\u093f\u092f\u094b\u0902 \u0915\u093e \u092e\u093f\u0936\u094d\u0930\u0923 \u0939\u0948\u0964"}'::jsonb, 'PUBLISHED', NOW(), NOW()),
(gen_random_uuid(), (SELECT id FROM places WHERE name = 'New Delhi' LIMIT 1), 'HISTORICAL', 'Historical Overview of New Delhi', 'New Delhi का ऐतिहासिक अवलोकन', '{"historical": "New Delhi has served as the capital for several empires, notably the Delhi Sultanate and the Mughals, before being rebuilt by the British in the 20th century.", "cultural": "It is a melting pot of cultures, featuring ancient monuments like Qutub Minar and Humayun''s Tomb alongside bustling modern markets and vibrant festivals."}'::jsonb, '{"historical": "\u0928\u0908 \u0926\u093f\u0932\u094d\u0932\u0940 \u0928\u0947 20\u0935\u0940\u0902 \u0938\u0926\u0940 \u092e\u0947\u0902 \u0905\u0902\u0917\u094d\u0930\u0947\u091c\u094b\u0902 \u0926\u094d\u0935\u093e\u0930\u093e \u092b\u093f\u0930 \u0938\u0947 \u092c\u0928\u093e\u090f \u091c\u093e\u0928\u0947 \u0938\u0947 \u092a\u0939\u0932\u0947 \u0926\u093f\u0932\u094d\u0932\u0940 \u0938\u0932\u094d\u0924\u0928\u0924 \u0914\u0930 \u092e\u0941\u0917\u0932\u094b\u0902 \u091c\u0948\u0938\u0947 \u0915\u0908 \u0938\u093e\u092e\u094d\u0930\u093e\u091c\u094d\u092f\u094b\u0902 \u0915\u0940 \u0930\u093e\u091c\u0927\u093e\u0928\u0940 \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u0915\u093e\u092e \u0915\u093f\u092f\u093e \u0939\u0948\u0964", "cultural": "\u092f\u0939 \u0938\u0902\u0938\u094d\u0915\u0943\u0924\u093f\u092f\u094b\u0902 \u0915\u093e \u0938\u0902\u0917\u092e \u0939\u0948, \u091c\u093f\u0938\u092e\u0947\u0902 \u0915\u0941\u0924\u0941\u092c \u092e\u0940\u0928\u093e\u0930 \u0914\u0930 \u0939\u0941\u092e\u093e\u092f\u0942\u0902 \u0915\u093e \u092e\u0915\u092c\u0930\u093e \u091c\u0948\u0938\u0947 \u092a\u094d\u0930\u093e\u091a\u0940\u0928 \u0938\u094d\u092e\u093e\u0930\u0915\u094b\u0902 \u0915\u0947 \u0938\u093e\u0925-\u0938\u093e\u0925 \u0906\u0927\u0941\u0928\u093f\u0915 \u092c\u093e\u091c\u093e\u0930 \u0936\u093e\u092e\u093f\u0932 \u0939\u0948\u0902\u0964"}'::jsonb, 'PUBLISHED', NOW(), NOW()),
(gen_random_uuid(), (SELECT id FROM places WHERE name = 'Gwalior' LIMIT 1), 'HISTORICAL', 'Historical Overview of Gwalior', 'Gwalior का ऐतिहासिक अवलोकन', '{"historical": "Gwalior has been ruled by various dynasties including the Tomars, Mughals, and Scindias. The magnificent Gwalior Fort has stood defensively for centuries.", "cultural": "Known as the city of music, Gwalior is the birthplace of the great musician Tansen and has a rich tradition of Hindustani classical music."}'::jsonb, '{"historical": "\u0917\u094d\u0935\u093e\u0932\u093f\u092f\u0930 \u092a\u0930 \u0924\u094b\u092e\u0930, \u092e\u0941\u0917\u0932 \u0914\u0930 \u0938\u093f\u0902\u0927\u093f\u092f\u093e \u0938\u0939\u093f\u0924 \u0935\u093f\u092d\u093f\u0928\u094d\u0928 \u0930\u093e\u091c\u0935\u0902\u0936\u094b\u0902 \u0915\u093e \u0936\u093e\u0938\u0928 \u0930\u0939\u093e \u0939\u0948\u0964 \u0936\u093e\u0928\u0926\u093e\u0930 \u0917\u094d\u0935\u093e\u0932\u093f\u092f\u0930 \u0915\u093f\u0932\u093e \u0938\u0926\u093f\u092f\u094b\u0902 \u0938\u0947 \u0930\u0915\u094d\u0937\u093e\u0924\u094d\u092e\u0915 \u0930\u0942\u092a \u0938\u0947 \u0916\u0921\u093c\u093e \u0939\u0948\u0964", "cultural": "\u0938\u0902\u0917\u0940\u0924 \u0915\u0947 \u0936\u0939\u0930 \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u091c\u093e\u0928\u093e \u091c\u093e\u0928\u0947 \u0935\u093e\u0932\u093e \u0917\u094d\u0935\u093e\u0932\u093f\u092f\u0930 \u092e\u0939\u093e\u0928 \u0938\u0902\u0917\u0940\u0924\u0915\u093e\u0930 \u0924\u093e\u0928\u0938\u0947\u0928 \u0915\u093e \u091c\u0928\u094d\u092e\u0938\u094d\u0925\u093e\u0928 \u0939\u0948 \u0914\u0930 \u092f\u0939\u093e\u0902 \u0939\u093f\u0902\u0926\u0941\u0938\u094d\u0924\u093e\u0928\u0940 \u0936\u093e\u0938\u094d\u0924\u094d\u0930\u0940\u092f \u0938\u0902\u0917\u0940\u0924 \u0915\u0940 \u0938\u092e\u0943\u0926\u094d\u0927 \u092a\u0930\u0902\u092a\u0930\u093e \u0939\u0948\u0964"}'::jsonb, 'PUBLISHED', NOW(), NOW()),
(gen_random_uuid(), (SELECT id FROM places WHERE name = 'Mathura' LIMIT 1), 'HISTORICAL', 'Historical Overview of Mathura', 'Mathura का ऐतिहासिक अवलोकन', '{"historical": "Mathura is universally revered as the birthplace of Lord Krishna. It was a major economic and religious hub in ancient India, especially during the Kushan period.", "cultural": "The city''s culture is deeply intertwined with Krishna devotion, featuring vibrant Holi celebrations and numerous ancient temples along the Yamuna river."}'::jsonb, '{"historical": "\u092e\u0925\u0941\u0930\u093e \u0915\u094b \u092d\u0917\u0935\u093e\u0928 \u0915\u0943\u0937\u094d\u0923 \u0915\u0947 \u091c\u0928\u094d\u092e\u0938\u094d\u0925\u093e\u0928 \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u0935\u093f\u0936\u094d\u0935 \u0938\u094d\u0924\u0930 \u092a\u0930 \u092a\u0942\u091c\u093e \u091c\u093e\u0924\u093e \u0939\u0948\u0964 \u092f\u0939 \u092a\u094d\u0930\u093e\u091a\u0940\u0928 \u092d\u093e\u0930\u0924 \u092e\u0947\u0902, \u0935\u093f\u0936\u0947\u0937\u0915\u0930 \u0915\u0941\u0937\u093e\u0923 \u0915\u093e\u0932 \u200b\u200b\u092e\u0947\u0902 \u090f\u0915 \u092a\u094d\u0930\u092e\u0941\u0916 \u0915\u0947\u0902\u0926\u094d\u0930 \u0925\u093e\u0964", "cultural": "\u0907\u0938 \u0936\u0939\u0930 \u0915\u0940 \u0938\u0902\u0938\u094d\u0915\u0943\u0924\u093f \u0915\u0943\u0937\u094d\u0923 \u092d\u0915\u094d\u0924\u093f \u0915\u0947 \u0938\u093e\u0925 \u0917\u0939\u0930\u093e\u0908 \u0938\u0947 \u091c\u0941\u0921\u093c\u0940 \u0939\u0941\u0908 \u0939\u0948, \u091c\u093f\u0938\u092e\u0947\u0902 \u091c\u0940\u0935\u0902\u0924 \u0939\u094b\u0932\u0940 \u0909\u0924\u094d\u0938\u0935 \u0914\u0930 \u092f\u092e\u0941\u0928\u093e \u0928\u0926\u0940 \u0915\u0947 \u0915\u093f\u0928\u093e\u0930\u0947 \u0915\u0908 \u092a\u094d\u0930\u093e\u091a\u0940\u0928 \u092e\u0902\u0926\u093f\u0930 \u0939\u0948\u0902\u0964"}'::jsonb, 'PUBLISHED', NOW(), NOW()),
(gen_random_uuid(), (SELECT id FROM places WHERE name = 'Hampi Temples' LIMIT 1), 'HISTORICAL', 'Historical Overview of Hampi Temples', 'Hampi Temples का ऐतिहासिक अवलोकन', '{"historical": "Hampi was the grand capital of the Vijayanagara Empire in the 14th century, once one of the richest and largest cities in the world before its destruction.", "cultural": "Its breathtaking ruins and rock-cut chariot temples reflect incredible architectural brilliance, drawing historians and devotees alike to its surreal landscape."}'::jsonb, '{"historical": "\u0939\u092e\u094d\u092a\u0940 14\u0935\u0940\u0902 \u0938\u0926\u0940 \u092e\u0947\u0902 \u0935\u093f\u091c\u092f\u0928\u0917\u0930 \u0938\u093e\u092e\u094d\u0930\u093e\u091c\u094d\u092f \u0915\u0940 \u092d\u0935\u094d\u092f \u0930\u093e\u091c\u0927\u093e\u0928\u0940 \u0925\u0940, \u091c\u094b \u0915\u092d\u0940 \u0926\u0941\u0928\u093f\u092f\u093e \u0915\u0947 \u0938\u092c\u0938\u0947 \u0905\u092e\u0940\u0930 \u0914\u0930 \u0938\u092c\u0938\u0947 \u092c\u0921\u093c\u0947 \u0936\u0939\u0930\u094b\u0902 \u092e\u0947\u0902 \u0938\u0947 \u090f\u0915 \u0925\u0940\u0964", "cultural": "\u0907\u0938\u0915\u0947 \u0932\u0941\u092d\u093e\u0935\u0928\u0947 \u0916\u0902\u0921\u0939\u0930 \u0914\u0930 \u0930\u0949\u0915-\u0915\u091f \u0930\u0925 \u092e\u0902\u0926\u093f\u0930 \u0905\u0935\u093f\u0936\u094d\u0935\u0938\u0928\u0940\u092f \u0935\u093e\u0938\u094d\u0924\u0941\u0915\u0932\u093e \u0915\u0940 \u092a\u094d\u0930\u0924\u093f\u092d\u093e \u0915\u094b \u0926\u0930\u094d\u0936\u093e\u0924\u0947 \u0939\u0948\u0902, \u091c\u094b \u0907\u0924\u093f\u0939\u093e\u0938\u0915\u093e\u0930\u094b\u0902 \u0914\u0930 \u092d\u0915\u094d\u0924\u094b\u0902 \u0915\u094b \u0906\u0915\u0930\u094d\u0937\u093f\u0924 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902\u0964"}'::jsonb, 'PUBLISHED', NOW(), NOW()),
(gen_random_uuid(), (SELECT id FROM places WHERE name = 'Chola Temples' LIMIT 1), 'HISTORICAL', 'Historical Overview of Chola Temples', 'Chola Temples का ऐतिहासिक अवलोकन', '{"historical": "The Great Living Chola Temples were built by kings of the Chola Empire between the 11th and 12th centuries in Tamil Nadu, demonstrating unprecedented engineering.", "cultural": "These temples are marvels of Dravidian architecture, featuring towering Vimanas, detailed bronze casting, and intricate stone carvings dedicated to Lord Shiva."}'::jsonb, '{"historical": "\u092e\u0939\u093e\u0928 \u091a\u094b\u0932 \u092e\u0902\u0926\u093f\u0930\u094b\u0902 \u0915\u093e \u0928\u093f\u0930\u094d\u092e\u093e\u0923 11\u0935\u0940\u0902 \u0914\u0930 12\u0935\u0940\u0902 \u0938\u0926\u0940 \u0915\u0947 \u092c\u0940\u091a \u0924\u092e\u093f\u0932\u0928\u093e\u0921\u0941 \u092e\u0947\u0902 \u091a\u094b\u0932 \u0938\u093e\u092e\u094d\u0930\u093e\u091c\u094d\u092f \u0915\u0947 \u0930\u093e\u091c\u093e\u0913\u0902 \u0926\u094d\u0935\u093e\u0930\u093e \u0915\u093f\u092f\u093e \u0917\u092f\u093e \u0925\u093e, \u091c\u094b \u0905\u092d\u0942\u0924\u092a\u0942\u0930\u094d\u0935 \u0907\u0902\u091c\u0940\u0928\u093f\u092f\u0930\u093f\u0902\u0917 \u0915\u093e \u092a\u094d\u0930\u0926\u0930\u094d\u0936\u0928 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902\u0964", "cultural": "\u092f\u0947 \u092e\u0902\u0926\u093f\u0930 \u0926\u094d\u0930\u0935\u093f\u0921\u093c \u0935\u093e\u0938\u094d\u0924\u0941\u0915\u0932\u093e \u0915\u0947 \u091a\u092e\u0924\u094d\u0915\u093e\u0930 \u0939\u0948\u0902, \u091c\u093f\u0928\u092e\u0947\u0902 \u090a\u0902\u091a\u0947 \u0935\u093f\u092e\u093e\u0928, \u0935\u093f\u0938\u094d\u0924\u0943\u0924 \u0915\u093e\u0902\u0938\u094d\u092f \u0915\u093e\u0938\u094d\u091f\u093f\u0902\u0917 \u0914\u0930 \u092d\u0917\u0935\u093e\u0928 \u0936\u093f\u0935 \u0915\u094b \u0938\u092e\u0930\u094d\u092a\u093f\u0924 \u091c\u091f\u093f\u0932 \u092a\u0924\u094d\u0925\u0930 \u0915\u0940 \u0928\u0915\u094d\u0915\u093e\u0936\u0940 \u0936\u093e\u092e\u093f\u0932 \u0939\u0948\u0964"}'::jsonb, 'PUBLISHED', NOW(), NOW()),
(gen_random_uuid(), (SELECT id FROM places WHERE name = 'Meenakshi Temple' LIMIT 1), 'HISTORICAL', 'Historical Overview of Meenakshi Temple', 'Meenakshi Temple का ऐतिहासिक अवलोकन', '{"historical": "Located in Madurai, this historic Hindu temple is dedicated to Goddess Meenakshi. The current structure was largely built during the Nayak dynasty in the 16th century.", "cultural": "It is the cultural and spiritual heart of Madurai, famous for its colorful gopurams (towers), the Hall of Thousand Pillars, and bustling temple festivals."}'::jsonb, '{"historical": "\u092e\u0926\u0941\u0930\u0948 \u092e\u0947\u0902 \u0938\u094d\u0925\u093f\u0924 \u092f\u0939 \u0910\u0924\u093f\u0939\u093e\u0938\u093f\u0915 \u0939\u093f\u0902\u0926\u0942 \u092e\u0902\u0926\u093f\u0930 \u0926\u0947\u0935\u0940 \u092e\u0940\u0928\u093e\u0915\u094d\u0937\u0940 \u0915\u094b \u0938\u092e\u0930\u094d\u092a\u093f\u0924 \u0939\u0948\u0964 \u0935\u0930\u094d\u0924\u092e\u093e\u0928 \u0938\u0902\u0930\u091a\u0928\u093e \u0915\u093e \u0928\u093f\u0930\u094d\u092e\u093e\u0923 \u092c\u0921\u093c\u0947 \u092a\u0948\u092e\u093e\u0928\u0947 \u092a\u0930 16\u0935\u0940\u0902 \u0936\u0924\u093e\u092c\u094d\u0926\u0940 \u092e\u0947\u0902 \u0928\u093e\u092f\u0915 \u0930\u093e\u091c\u0935\u0902\u0936 \u0915\u0947 \u0926\u094c\u0930\u093e\u0928 \u0915\u093f\u092f\u093e \u0917\u092f\u093e \u0925\u093e\u0964", "cultural": "\u092f\u0939 \u092e\u0926\u0941\u0930\u0948 \u0915\u093e \u0938\u093e\u0902\u0938\u094d\u0915\u0943\u0924\u093f\u0915 \u0914\u0930 \u0906\u0927\u094d\u092f\u093e\u0924\u094d\u092e\u093f\u0915 \u0915\u0947\u0902\u0926\u094d\u0930 \u0939\u0948, \u091c\u094b \u0905\u092a\u0928\u0947 \u0930\u0902\u0917\u0940\u0928 \u0917\u094b\u092a\u0941\u0930\u092e (\u091f\u093e\u0935\u0930\u094b\u0902), \u0939\u091c\u093e\u0930 \u0938\u094d\u0924\u0902\u092d\u094b\u0902 \u0915\u0947 \u0939\u0949\u0932 \u0914\u0930 \u092e\u0902\u0926\u093f\u0930 \u0915\u0947 \u0924\u094d\u092f\u094b\u0939\u093e\u0930\u094b\u0902 \u0915\u0947 \u0932\u093f\u090f \u092a\u094d\u0930\u0938\u093f\u0926\u094d\u0927 \u0939\u0948\u0964"}'::jsonb, 'PUBLISHED', NOW(), NOW()),
(gen_random_uuid(), (SELECT id FROM places WHERE name = 'Jyotirlingas of Maharashtra' LIMIT 1), 'HISTORICAL', 'Historical Overview of Jyotirlingas of Maharashtra', 'Jyotirlingas of Maharashtra का ऐतिहासिक अवलोकन', '{"historical": "Maharashtra is home to several ancient Jyotirlingas, including Trimbakeshwar, Bhimashankar, and Grishneshwar, deeply venerated since ancient times.", "cultural": "These shrines represent the fierce and infinite light of Lord Shiva, attracting millions of pilgrims yearly for deep spiritual fulfillment."}'::jsonb, '{"historical": "\u092e\u0939\u093e\u0930\u093e\u0937\u094d\u091f\u094d\u0930 \u0924\u094d\u0930\u094d\u092f\u0902\u092c\u0915\u0947\u0936\u094d\u0935\u0930, \u092d\u0940\u092e\u093e\u0936\u0902\u0915\u0930 \u0914\u0930 \u0918\u0943\u0937\u094d\u0923\u0947\u0936\u094d\u0935\u0930 \u0938\u0939\u093f\u0924 \u0915\u0908 \u092a\u094d\u0930\u093e\u091a\u0940\u0928 \u091c\u094d\u092f\u094b\u0924\u093f\u0930\u094d\u0932\u093f\u0902\u0917\u094b\u0902 \u0915\u093e \u0918\u0930 \u0939\u0948, \u091c\u093f\u0928\u0915\u0940 \u092a\u094d\u0930\u093e\u091a\u0940\u0928 \u0915\u093e\u0932 \u0938\u0947 \u0917\u0939\u0930\u0940 \u092a\u0942\u091c\u093e \u0915\u0940 \u091c\u093e\u0924\u0940 \u0939\u0948\u0964", "cultural": "\u092f\u0947 \u092e\u0902\u0926\u093f\u0930 \u092d\u0917\u0935\u093e\u0928 \u0936\u093f\u0935 \u0915\u0947 \u0905\u0928\u0902\u0924 \u092a\u094d\u0930\u0915\u093e\u0936 \u0915\u093e \u092a\u094d\u0930\u0924\u093f\u0928\u093f\u0927\u093f\u0924\u094d\u0935 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902, \u091c\u094b \u0939\u0930 \u0938\u093e\u0932 \u0932\u093e\u0916\u094b\u0902 \u0924\u0940\u0930\u094d\u0925\u092f\u093e\u0924\u094d\u0930\u093f\u092f\u094b\u0902 \u0915\u094b \u0906\u0927\u094d\u092f\u093e\u0924\u094d\u092e\u093f\u0915 \u092a\u0942\u0930\u094d\u0924\u093f \u0915\u0947 \u0932\u093f\u090f \u0906\u0915\u0930\u094d\u0937\u093f\u0924 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902\u0964"}'::jsonb, 'PUBLISHED', NOW(), NOW()),
(gen_random_uuid(), (SELECT id FROM places WHERE name = 'Jyotirlingas of Gujarat' LIMIT 1), 'HISTORICAL', 'Historical Overview of Jyotirlingas of Gujarat', 'Jyotirlingas of Gujarat का ऐतिहासिक अवलोकन', '{"historical": "Gujarat hosts Somnath, historically recognized as the first among the twelve Jyotirlingas, and Nageshwar. Somnath has been rebuilt several times after historical invasions.", "cultural": "The eternal resilience of Somnath is a symbol of faith and cultural perseverance, reflecting the unbreakable spirit of Indian spirituality."}'::jsonb, '{"historical": "\u0917\u0941\u091c\u0930\u093e\u0924 \u092e\u0947\u0902 \u0938\u094b\u092e\u0928\u093e\u0925 \u0939\u0948, \u091c\u093f\u0938\u0947 \u0910\u0924\u093f\u0939\u093e\u0938\u093f\u0915 \u0930\u0942\u092a \u0938\u0947 \u092c\u093e\u0930\u0939 \u091c\u094d\u092f\u094b\u0924\u093f\u0930\u094d\u0932\u093f\u0902\u0917\u094b\u0902 \u092e\u0947\u0902 \u0938\u0947 \u092a\u0939\u0932\u093e \u092e\u093e\u0928\u093e \u091c\u093e\u0924\u093e \u0939\u0948\u0964 \u0910\u0924\u093f\u0939\u093e\u0938\u093f\u0915 \u0906\u0915\u094d\u0930\u092e\u0923\u094b\u0902 \u0915\u0947 \u092c\u093e\u0926 \u0938\u094b\u092e\u0928\u093e\u0925 \u0915\u093e \u0915\u0908 \u092c\u093e\u0930 \u092a\u0941\u0928\u0930\u094d\u0928\u093f\u0930\u094d\u092e\u093e\u0923 \u0915\u093f\u092f\u093e \u0917\u092f\u093e \u0939\u0948\u0964", "cultural": "\u0938\u094b\u092e\u0928\u093e\u0925 \u0915\u093e \u0932\u091a\u0940\u0932\u093e\u092a\u0928 \u0906\u0938\u094d\u0925\u093e \u0914\u0930 \u0938\u093e\u0902\u0938\u094d\u0915\u0943\u0924\u093f\u0915 \u0926\u0943\u0922\u093c\u0924\u093e \u0915\u093e \u092a\u094d\u0930\u0924\u0940\u0915 \u0939\u0948, \u091c\u094b \u092d\u093e\u0930\u0924\u0940\u092f \u0906\u0927\u094d\u092f\u093e\u0924\u094d\u092e\u093f\u0915\u0924\u093e \u0915\u0940 \u0905\u091f\u0942\u091f \u092d\u093e\u0935\u0928\u093e \u0915\u094b \u0926\u0930\u094d\u0936\u093e\u0924\u093e \u0939\u0948\u0964"}'::jsonb, 'PUBLISHED', NOW(), NOW()),
(gen_random_uuid(), (SELECT id FROM places WHERE name = 'Jyotirlingas of Madhya Pradesh' LIMIT 1), 'HISTORICAL', 'Historical Overview of Jyotirlingas of Madhya Pradesh', 'Jyotirlingas of Madhya Pradesh का ऐतिहासिक अवलोकन', '{"historical": "Madhya Pradesh is blessed with Mahakaleshwar in Ujjain and Omkareshwar on the Narmada river, both acting as vital spiritual centers since antiquity.", "cultural": "Mahakaleshwar is uniquely known for its Bhasma Aarti, and both shrines play a massive role in the cultural and religious fabric of the region."}'::jsonb, '{"historical": "\u092e\u0927\u094d\u092f \u092a\u094d\u0930\u0926\u0947\u0936 \u0909\u091c\u094d\u091c\u0948\u0928 \u092e\u0947\u0902 \u092e\u0939\u093e\u0915\u093e\u0932\u0947\u0936\u094d\u0935\u0930 \u0914\u0930 \u0928\u0930\u094d\u092e\u0926\u093e \u0928\u0926\u0940 \u092a\u0930 \u0913\u0902\u0915\u093e\u0930\u0947\u0936\u094d\u0935\u0930 \u0915\u0947 \u0938\u093e\u0925 \u0927\u0928\u094d\u092f \u0939\u0948, \u091c\u094b \u092a\u094d\u0930\u093e\u091a\u0940\u0928 \u0915\u093e\u0932 \u0938\u0947 \u092e\u0939\u0924\u094d\u0935\u092a\u0942\u0930\u094d\u0923 \u0906\u0927\u094d\u092f\u093e\u0924\u094d\u092e\u093f\u0915 \u0915\u0947\u0902\u0926\u094d\u0930 \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u0915\u093e\u0930\u094d\u092f \u0915\u0930 \u0930\u0939\u0947 \u0939\u0948\u0902\u0964", "cultural": "\u092e\u0939\u093e\u0915\u093e\u0932\u0947\u0936\u094d\u0935\u0930 \u0935\u093f\u0936\u0947\u0937 \u0930\u0942\u092a \u0938\u0947 \u0905\u092a\u0928\u0940 \u092d\u0938\u094d\u092e \u0906\u0930\u0924\u0940 \u0915\u0947 \u0932\u093f\u090f \u091c\u093e\u0928\u093e \u091c\u093e\u0924\u093e \u0939\u0948, \u0914\u0930 \u092f\u0947 \u0926\u094b\u0928\u094b\u0902 \u092e\u0902\u0926\u093f\u0930 \u0915\u094d\u0937\u0947\u0924\u094d\u0930 \u0915\u0947 \u0938\u093e\u0902\u0938\u094d\u0915\u0943\u0924\u093f\u0915 \u0914\u0930 \u0927\u093e\u0930\u094d\u092e\u093f\u0915 \u0924\u093e\u0928\u0947-\u092c\u093e\u0928\u0947 \u092e\u0947\u0902 \u092c\u0921\u093c\u0940 \u092d\u0942\u092e\u093f\u0915\u093e \u0928\u093f\u092d\u093e\u0924\u0947 \u0939\u0948\u0902\u0964"}'::jsonb, 'PUBLISHED', NOW(), NOW()),
(gen_random_uuid(), (SELECT id FROM places WHERE name = 'Jyotirlingas of Uttar Pradesh' LIMIT 1), 'HISTORICAL', 'Historical Overview of Jyotirlingas of Uttar Pradesh', 'Jyotirlingas of Uttar Pradesh का ऐतिहासिक अवलोकन', '{"historical": "Kashi Vishwanath in Varanasi, Uttar Pradesh, is one of the holiest Jyotirlingas. Varanasi itself is considered one of the oldest continuously inhabited cities in the world.", "cultural": "The culture is defined by the sacred Ganges river, ancient ghats, daily Ganga Aarti, and a profound atmosphere of moksha (liberation)."}'::jsonb, '{"historical": "\u0909\u0924\u094d\u0924\u0930 \u092a\u094d\u0930\u0926\u0947\u0936 \u0915\u0947 \u0935\u093e\u0930\u093e\u0923\u0938\u0940 \u092e\u0947\u0902 \u0915\u093e\u0936\u0940 \u0935\u093f\u0936\u094d\u0935\u0928\u093e\u0925 \u0938\u092c\u0938\u0947 \u092a\u0935\u093f\u0924\u094d\u0930 \u091c\u094d\u092f\u094b\u0924\u093f\u0930\u094d\u0932\u093f\u0902\u0917\u094b\u0902 \u092e\u0947\u0902 \u0938\u0947 \u090f\u0915 \u0939\u0948\u0964 \u0935\u093e\u0930\u093e\u0923\u0938\u0940 \u0915\u094b \u0926\u0941\u0928\u093f\u092f\u093e \u0915\u0947 \u0938\u092c\u0938\u0947 \u092a\u0941\u0930\u093e\u0928\u0947 \u0932\u0917\u093e\u0924\u093e\u0930 \u092c\u0938\u0947 \u0936\u0939\u0930\u094b\u0902 \u092e\u0947\u0902 \u0938\u0947 \u090f\u0915 \u092e\u093e\u0928\u093e \u091c\u093e\u0924\u093e \u0939\u0948\u0964", "cultural": "\u0938\u0902\u0938\u094d\u0915\u0943\u0924\u093f \u0915\u094b \u092a\u0935\u093f\u0924\u094d\u0930 \u0917\u0902\u0917\u093e \u0928\u0926\u0940, \u092a\u094d\u0930\u093e\u091a\u0940\u0928 \u0918\u093e\u091f\u094b\u0902, \u0926\u0948\u0928\u093f\u0915 \u0917\u0902\u0917\u093e \u0906\u0930\u0924\u0940 \u0914\u0930 \u092e\u094b\u0915\u094d\u0937 \u0915\u0940 \u0917\u0939\u0930\u0940 \u092d\u093e\u0935\u0928\u093e \u0926\u094d\u0935\u093e\u0930\u093e \u092a\u0930\u093f\u092d\u093e\u0937\u093f\u0924 \u0915\u093f\u092f\u093e \u0917\u092f\u093e \u0939\u0948\u0964"}'::jsonb, 'PUBLISHED', NOW(), NOW()),
(gen_random_uuid(), (SELECT id FROM places WHERE name = 'Jyotirlingas of Uttarakhand' LIMIT 1), 'HISTORICAL', 'Historical Overview of Jyotirlingas of Uttarakhand', 'Jyotirlingas of Uttarakhand का ऐतिहासिक अवलोकन', '{"historical": "Kedarnath, situated in the Himalayas, is a revered Jyotirlinga established by Adi Shankaracharya. It boasts a rich history intertwined with the Mahabharata.", "cultural": "Accessible only by a challenging trek, the temple symbolizes divine purity and resilience against extreme nature, serving as the ultimate pilgrimage destination."}'::jsonb, '{"historical": "\u0939\u093f\u092e\u093e\u0932\u092f \u092e\u0947\u0902 \u0938\u094d\u0925\u093f\u0924 \u0915\u0947\u0926\u093e\u0930\u0928\u093e\u0925, \u0906\u0926\u093f \u0936\u0902\u0915\u0930\u093e\u091a\u093e\u0930\u094d\u092f \u0926\u094d\u0935\u093e\u0930\u093e \u0938\u094d\u0925\u093e\u092a\u093f\u0924 \u090f\u0915 \u092a\u0942\u091c\u0928\u0940\u092f \u091c\u094d\u092f\u094b\u0924\u093f\u0930\u094d\u0932\u093f\u0902\u0917 \u0939\u0948\u0964 \u0907\u0938\u0915\u093e \u092e\u0939\u093e\u092d\u093e\u0930\u0924 \u0938\u0947 \u091c\u0941\u0921\u093c\u093e \u090f\u0915 \u0938\u092e\u0943\u0926\u094d\u0927 \u0907\u0924\u093f\u0939\u093e\u0938 \u0939\u0948\u0964", "cultural": "\u0915\u0947\u0935\u0932 \u090f\u0915 \u0915\u0920\u093f\u0928 \u091f\u094d\u0930\u0947\u0915 \u0926\u094d\u0935\u093e\u0930\u093e \u092a\u0939\u0941\u0901\u091a\u093e \u091c\u093e \u0938\u0915\u0928\u0947 \u0935\u093e\u0932\u093e \u092f\u0939 \u092e\u0902\u0926\u093f\u0930 \u091a\u0930\u092e \u092a\u094d\u0930\u0915\u0943\u0924\u093f \u0915\u0947 \u0916\u093f\u0932\u093e\u092b \u0926\u093f\u0935\u094d\u092f \u092a\u0935\u093f\u0924\u094d\u0930\u0924\u093e \u0914\u0930 \u0932\u091a\u0940\u0932\u0947\u092a\u0928 \u0915\u093e \u092a\u094d\u0930\u0924\u0940\u0915 \u0939\u0948\u0964"}'::jsonb, 'PUBLISHED', NOW(), NOW()),
(gen_random_uuid(), (SELECT id FROM places WHERE name = 'Jyotirlingas of Jharkhand' LIMIT 1), 'HISTORICAL', 'Historical Overview of Jyotirlingas of Jharkhand', 'Jyotirlingas of Jharkhand का ऐतिहासिक अवलोकन', '{"historical": "Baidyanath Jyotirlinga in Deoghar is steeped in legends of Ravana worshipping Lord Shiva, making it a place of immense mythological importance.", "cultural": "The Shravani Mela brings millions of Kanwariyas carrying holy water from the Ganges to offer at the lingam in a spectacular display of devotion."}'::jsonb, '{"historical": "\u0926\u0947\u0935\u0918\u0930 \u092e\u0947\u0902 \u092c\u0948\u0926\u094d\u092f\u0928\u093e\u0925 \u091c\u094d\u092f\u094b\u0924\u093f\u0930\u094d\u0932\u093f\u0902\u0917 \u0930\u093e\u0935\u0923 \u0926\u094d\u0935\u093e\u0930\u093e \u092d\u0917\u0935\u093e\u0928 \u0936\u093f\u0935 \u0915\u0940 \u092a\u0942\u091c\u093e \u0915\u0930\u0928\u0947 \u0915\u0940 \u0915\u093f\u0902\u0935\u0926\u0902\u0924\u093f\u092f\u094b\u0902 \u0938\u0947 \u092d\u0930\u093e \u0939\u0941\u0906 \u0939\u0948, \u091c\u094b \u0907\u0938\u0947 \u0905\u0924\u094d\u092f\u0927\u093f\u0915 \u092a\u094c\u0930\u093e\u0923\u093f\u0915 \u092e\u0939\u0924\u094d\u0935 \u0915\u093e \u0938\u094d\u0925\u093e\u0928 \u092c\u0928\u093e\u0924\u093e \u0939\u0948\u0964", "cultural": "\u0936\u094d\u0930\u093e\u0935\u0923\u0940 \u092e\u0947\u0932\u0947 \u092e\u0947\u0902 \u0932\u093e\u0916\u094b\u0902 \u0915\u093e\u0902\u0935\u0930\u093f\u090f \u0917\u0902\u0917\u093e \u0938\u0947 \u092a\u0935\u093f\u0924\u094d\u0930 \u091c\u0932 \u0932\u0947\u0915\u0930 \u092d\u0915\u094d\u0924\u093f \u0915\u0947 \u0936\u093e\u0928\u0926\u093e\u0930 \u092a\u094d\u0930\u0926\u0930\u094d\u0936\u0928 \u0915\u0947 \u0938\u093e\u0925 \u0932\u093f\u0902\u0917\u092e \u092a\u0930 \u091a\u0922\u093c\u093e\u0928\u0947 \u0906\u0924\u0947 \u0939\u0948\u0902\u0964"}'::jsonb, 'PUBLISHED', NOW(), NOW()),
(gen_random_uuid(), (SELECT id FROM places WHERE name = 'Jyotirlingas of Andhra Pradesh' LIMIT 1), 'HISTORICAL', 'Historical Overview of Jyotirlingas of Andhra Pradesh', 'Jyotirlingas of Andhra Pradesh का ऐतिहासिक अवलोकन', '{"historical": "Mallikarjuna Jyotirlinga in Srisailam is uniquely located on the Nallamala hills. It has patronized by various kings from the Chalukya and Vijayanagara empires.", "cultural": "It is revered as both a Jyotirlinga and a Shakti Peetha, making it a highly sacred site for both Shaivites and Shaktism followers."}'::jsonb, '{"historical": "\u0936\u094d\u0930\u0940\u0936\u0948\u0932\u092e \u092e\u0947\u0902 \u092e\u0932\u094d\u0932\u093f\u0915\u093e\u0930\u094d\u091c\u0941\u0928 \u091c\u094d\u092f\u094b\u0924\u093f\u0930\u094d\u0932\u093f\u0902\u0917 \u0928\u0932\u094d\u0932\u093e\u092e\u093e\u0932\u093e \u092a\u0939\u093e\u0921\u093c\u093f\u092f\u094b\u0902 \u092a\u0930 \u0938\u094d\u0925\u093f\u0924 \u0939\u0948\u0964 \u0907\u0938\u0947 \u091a\u093e\u0932\u0941\u0915\u094d\u092f \u0914\u0930 \u0935\u093f\u091c\u092f\u0928\u0917\u0930 \u0938\u093e\u092e\u094d\u0930\u093e\u091c\u094d\u092f\u094b\u0902 \u0915\u0947 \u0935\u093f\u092d\u093f\u0928\u094d\u0928 \u0930\u093e\u091c\u093e\u0913\u0902 \u0926\u094d\u0935\u093e\u0930\u093e \u0938\u0902\u0930\u0915\u094d\u0937\u0923 \u0926\u093f\u092f\u093e \u0917\u092f\u093e \u0939\u0948\u0964", "cultural": "\u0907\u0938\u0947 \u091c\u094d\u092f\u094b\u0924\u093f\u0930\u094d\u0932\u093f\u0902\u0917 \u0914\u0930 \u0936\u0915\u094d\u0924\u093f\u092a\u0940\u0920 \u0926\u094b\u0928\u094b\u0902 \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u092a\u0942\u091c\u093e \u091c\u093e\u0924\u093e \u0939\u0948, \u091c\u094b \u0907\u0938\u0947 \u0936\u0948\u0935 \u0914\u0930 \u0936\u093e\u0915\u094d\u0924 \u0926\u094b\u0928\u094b\u0902 \u0905\u0928\u0941\u092f\u093e\u092f\u093f\u092f\u094b\u0902 \u0915\u0947 \u0932\u093f\u090f \u0905\u0924\u094d\u092f\u0927\u093f\u0915 \u092a\u0935\u093f\u0924\u094d\u0930 \u0938\u094d\u0925\u0932 \u092c\u0928\u093e\u0924\u093e \u0939\u0948\u0964"}'::jsonb, 'PUBLISHED', NOW(), NOW()),
(gen_random_uuid(), (SELECT id FROM places WHERE name = 'Jyotirlingas of Tamil Nadu' LIMIT 1), 'HISTORICAL', 'Historical Overview of Jyotirlingas of Tamil Nadu', 'Jyotirlingas of Tamil Nadu का ऐतिहासिक अवलोकन', '{"historical": "Rameshwaram is home to the Ramanathaswamy Temple, deeply linked to the Ramayana where Lord Rama worshipped Shiva before crossing to Lanka.", "cultural": "Known for its magnificent corridors and 22 holy water teerthams, it holds unparalleled significance for Hindus seeking spiritual cleansing."}'::jsonb, '{"historical": "\u0930\u093e\u092e\u0947\u0936\u094d\u0935\u0930\u092e \u0930\u093e\u092e\u0928\u093e\u0925\u0938\u094d\u0935\u093e\u092e\u0940 \u092e\u0902\u0926\u093f\u0930 \u0915\u093e \u0918\u0930 \u0939\u0948, \u091c\u094b \u0930\u093e\u092e\u093e\u092f\u0923 \u0938\u0947 \u0917\u0939\u0930\u093e\u0908 \u0938\u0947 \u091c\u0941\u0921\u093c\u093e \u0939\u0941\u0906 \u0939\u0948 \u091c\u0939\u093e\u0902 \u092d\u0917\u0935\u093e\u0928 \u0930\u093e\u092e \u0928\u0947 \u0932\u0902\u0915\u093e \u092a\u093e\u0930 \u0915\u0930\u0928\u0947 \u0938\u0947 \u092a\u0939\u0932\u0947 \u0936\u093f\u0935 \u0915\u0940 \u092a\u0942\u091c\u093e \u0915\u0940 \u0925\u0940\u0964", "cultural": "\u0905\u092a\u0928\u0947 \u0936\u093e\u0928\u0926\u093e\u0930 \u0917\u0932\u093f\u092f\u093e\u0930\u094b\u0902 \u0914\u0930 22 \u092a\u0935\u093f\u0924\u094d\u0930 \u091c\u0932 \u0924\u0940\u0930\u094d\u0925\u094b\u0902 \u0915\u0947 \u0932\u093f\u090f \u091c\u093e\u0928\u093e \u091c\u093e\u0928\u0947 \u0935\u093e\u0932\u093e, \u092f\u0939 \u0906\u0927\u094d\u092f\u093e\u0924\u094d\u092e\u093f\u0915 \u0936\u0941\u0926\u094d\u0927\u093f \u091a\u093e\u0939\u0928\u0947 \u0935\u093e\u0932\u0947 \u0939\u093f\u0902\u0926\u0941\u0913\u0902 \u0915\u0947 \u0932\u093f\u090f \u0905\u0926\u094d\u0935\u093f\u0924\u0940\u092f \u092e\u0939\u0924\u094d\u0935 \u0930\u0916\u0924\u093e \u0939\u0948\u0964"}'::jsonb, 'PUBLISHED', NOW(), NOW());